11	/*
12	 * Negative return values handled by nJSVM interpreter as special events.
13	 * The values must be in range from -1 to -11, because -12 is minimal jump
14	 * offset on 32-bit platforms.
15	 *    0  (NJS_OK)   :  njs_vmcode_stop() has stopped execution,
16	 *                          execution successfully finished
17	 *    -1 (NJS_ERROR):  error or exception;
18	 *    -2 .. -11:                 not used.
19	 */
20	
21	/* The last return value which preempts execution. */
22	#define NJS_PREEMPT                     (-11)
