248	njs_inline int
249	njs_parser_height(njs_parser_t *parser, njs_queue_link_t *link)
250	{
251	    int               height;
252	    njs_queue_link_t  *lnk;
253	
254	    height = 0;
255	
256	   for (lnk = njs_queue_first(&parser->stack);
257	        lnk != njs_queue_tail(&parser->stack);
258	        lnk = njs_queue_next(lnk))
259	   {
260	       if (link != lnk) {
261	            height++;
262	            continue;
263	       }
264	
265	       return height;
266	   }
267	
268	   return -1;
269	}
270	
271	#define njs_parser_next(parser, _state)                                     \
272	    do {                                                                    \
273	        const char *name = njs_stringify(_state);                           \
274	        if (memcmp(name, "entry->state", njs_min(njs_strlen(name), 12))) {  \
275	            njs_printf("next(%s)\n", name + njs_length("njs_parser_"));     \
276	        }                                                                   \
277	                                                                            \
278	        parser->state = _state;                                             \
279	    } while(0)
280	
281	#endif
