285	njs_parser_stack_pop(njs_parser_t *parser)
286	{
287	    njs_queue_link_t          *link;
288	    njs_parser_stack_entry_t  *entry;
289	
290	    entry = njs_queue_link_data(njs_queue_first(&parser->stack),
291	                                njs_parser_stack_entry_t, link);
292	
293	    link = njs_queue_first(&parser->stack);
294	    njs_queue_remove(link);
295	
296	#ifdef NJS_PARSER_DEBUG
297	    njs_printf("  stack_pop(%d)\n",
298	               njs_parser_height(parser, njs_queue_last(&parser->stack)));
299	#endif
300	
301	    njs_parser_next(parser, entry->state);
302	
303	    parser->target = entry->node;
304	
305	    njs_mp_free(parser->vm->mem_pool, entry);
306	
307	    return NJS_OK;
308	}
