30	njs_vm_t *
31	njs_vm_create(njs_vm_opt_t *options)
32	{
33	    njs_mp_t      *mp;
34	    njs_vm_t      *vm;
35	    njs_int_t     ret;
36	    njs_uint_t    i;
37	    njs_module_t  **addons;
38	
39	    mp = njs_mp_fast_create(2 * njs_pagesize(), 128, 512, 16);
40	    if (njs_slow_path(mp == NULL)) {
41	        return NULL;
42	    }
43	
44	    vm = njs_mp_zalign(mp, sizeof(njs_value_t), sizeof(njs_vm_t));
45	    if (njs_slow_path(vm == NULL)) {
46	        return NULL;
47	    }
48	
49	    vm->mem_pool = mp;
50	
51	    ret = njs_regexp_init(vm);
52	    if (njs_slow_path(ret != NJS_OK)) {
53	        return NULL;
54	    }
55	
56	    njs_flathsh_init(&vm->values_hash);
57	
58	    vm->options = *options;
59	
60	    if (options->shared != NULL) {
61	        vm->shared = options->shared;
62	
63	    } else {
64	        ret = njs_builtin_objects_create(vm);
65	        if (njs_slow_path(ret != NJS_OK)) {
66	            return NULL;
67	        }
68	    }
69	
70	    vm->external = options->external;
71	
72	    vm->spare_stack_size = options->max_stack_size;
73	
74	    vm->trace.level = NJS_LEVEL_TRACE;
75	    vm->trace.size = 2048;
76	    vm->trace.data = vm;
77	
78	    if (options->init) {
79	        ret = njs_vm_runtime_init(vm);
80	        if (njs_slow_path(ret != NJS_OK)) {
81	            return NULL;
82	        }
83	    }
84	
85	    for (i = 0; njs_modules[i] != NULL; i++) {
86	        if (njs_modules[i]->preinit == NULL) {
87	            continue;
88	        }
89	
90	        ret = njs_modules[i]->preinit(vm);
91	        if (njs_slow_path(ret != NJS_OK)) {
92	            return NULL;
93	        }
94	    }
95	
96	    if (options->addons != NULL) {
97	        addons = options->addons;
98	        for (i = 0; addons[i] != NULL; i++) {
99	            if (addons[i]->preinit == NULL) {
100	                continue;
101	            }
102	
103	            ret = addons[i]->preinit(vm);
104	            if (njs_slow_path(ret != NJS_OK)) {
105	                return NULL;
106	            }
107	        }
108	    }
109	
110	    ret = njs_vm_protos_init(vm, &vm->global_value);
111	    if (njs_slow_path(ret != NJS_OK)) {
112	        return NULL;
113	    }
114	
115	    for (i = 0; njs_modules[i] != NULL; i++) {
116	        if (njs_modules[i]->init == NULL) {
117	            continue;
118	        }
119	
120	        ret = njs_modules[i]->init(vm);
121	        if (njs_slow_path(ret != NJS_OK)) {
122	            return NULL;
123	        }
124	    }
125	
126	    if (options->addons != NULL) {
127	        addons = options->addons;
128	        for (i = 0; addons[i] != NULL; i++) {
129	            if (addons[i]->init == NULL) {
130	                continue;
131	            }
132	
133	            ret = addons[i]->init(vm);
134	            if (njs_slow_path(ret != NJS_OK)) {
135	                return NULL;
136	            }
137	        }
138	    }
139	
140	    if (njs_scope_undefined_index(vm, 0) == NJS_INDEX_ERROR) {
141	        return NULL;
142	    }
143	
144	    return vm;
145	}
