159	                                              NJS_OBJ_TYPE_MAX + 8,
160	                                              sizeof(njs_function_t));
161	        if (njs_slow_path(shared->constructors == NULL)) {
162	            njs_memory_error(vm);
163	            return -1;
164	        }
165	
166	        shared->prototypes = njs_arr_create(vm->mem_pool,
167	                                              NJS_OBJ_TYPE_MAX + 8,
168	                                              sizeof(njs_object_prototype_t));
169	        if (njs_slow_path(shared->prototypes == NULL)) {
170	            njs_memory_error(vm);
171	            return -1;
172	        }
173	    }
174	
175	    ctor = njs_arr_add(shared->constructors);
176	    if (njs_slow_path(ctor == NULL)) {
177	        njs_memory_error(vm);
178	        return -1;
179	    }
180	
181	    prototype = njs_arr_add(shared->prototypes);
182	    if (njs_slow_path(prototype == NULL)) {
183	        njs_memory_error(vm);
184	        return -1;
185	    }
186	
187	    njs_assert(shared->constructors->items == shared->prototypes->items);
188	
189	    return shared->constructors->items - 1;
190	}
