175	njs_inline njs_int_t
176	njs_value_to_key2(njs_vm_t *vm, njs_value_t *dst, njs_value_t *value,
177	    njs_bool_t convert)
178	{
179	    njs_int_t    ret;
180	    njs_value_t  primitive;
181	
182	    if (njs_slow_path(!njs_is_primitive(value))) {
183	        if (njs_slow_path(njs_is_object_symbol(value))) {
184	            /* should fail */
185	            value = njs_object_value(value);
186	
187	        } else {
188	            if (convert) {
189	                ret = njs_value_to_primitive(vm, &primitive, value,
190	                                             NJS_HINT_STRING);
191	
192	            } else {
193	                ret = njs_object_to_string(vm, value, &primitive);
194	            }
195	
196	            if (njs_slow_path(ret != NJS_OK)) {
197	                return ret;
198	            }
199	
200	            value = &primitive;
201	        }
202	    }
203	
204	    return njs_primitive_value_to_key(vm, dst, value);
205	}
