1125	njs_inline njs_bool_t
1126	njs_values_same(njs_vm_t *vm, const njs_value_t *val1, const njs_value_t *val2)
1127	{
1128	    double  num1, num2;
1129	
1130	    if (val1->type != val2->type) {
1131	        return 0;
1132	    }
1133	
1134	    if (njs_is_numeric(val1)) {
1135	
1136	        if (njs_is_undefined(val1)) {
1137	            return 1;
1138	        }
1139	
1140	        num1 = njs_number(val1);
1141	        num2 = njs_number(val2);
1142	
1143	        if (njs_slow_path(isnan(num1) && isnan(num2))) {
1144	            return 1;
1145	        }
1146	
1147	        if (njs_slow_path(num1 == 0 && num2 == 0
1148	                          && (signbit(num1) ^ signbit(num2))))
1149	        {
1150	            return 0;
1151	        }
1152	
1153	        /* Infinities are handled correctly by comparision. */
1154	        return num1 == num2;
1155	    }
1156	
1157	    return njs_values_same_non_numeric(vm, val1, val2);
1158	}
