30	{
31	    size_t       size;
32	    njs_value_t  **refs, *values;
33	
34	    size = (count * sizeof(njs_value_t *)) + (count * sizeof(njs_value_t));
35	
36	    refs = njs_mp_alloc(vm->mem_pool, size);
37	    if (njs_slow_path(refs == NULL)) {
