53	
54	    var = njs_variable_scope_add(parser, root, scope, atom_id,
55	                                 NJS_VARIABLE_FUNCTION, NJS_INDEX_ERROR);
56	    if (njs_slow_path(var == NULL)) {
57	        return NULL;
58	    }
59	
60	    root = njs_function_scope(scope);
61	    if (njs_slow_path(root == NULL)) {
62	        return NULL;
63	    }
64	
65	    ctor = parser->node->token_type != NJS_TOKEN_ASYNC_FUNCTION_DECLARATION;
66	
67	    lambda = njs_function_lambda_alloc(parser->vm, ctor);
68	    if (lambda == NULL) {
