71	
72	    njs_set_invalid(&var->value);
73	    var->value.data.u.lambda = lambda;
74	
75	    declr = njs_variable_scope_function_add(parser, root);
76	    if (njs_slow_path(declr == NULL)) {
77	        return NULL;
