391	njs_vm_t *
392	njs_vm_clone(njs_vm_t *vm, njs_external_ptr_t external)
393	{
394	    njs_mp_t     *nmp;
395	    njs_vm_t     *nvm;
396	    njs_int_t    ret;
397	    njs_value_t  **global, **value;
398	
399	    njs_thread_log_debug("CLONE:");
400	
401	    if (vm->options.interactive) {
402	        return NULL;
403	    }
404	
405	    nmp = njs_mp_fast_create(2 * njs_pagesize(), 128, 512, 16);
406	    if (njs_slow_path(nmp == NULL)) {
407	        return NULL;
408	    }
409	
410	    nvm = njs_mp_align(nmp, sizeof(njs_value_t), sizeof(njs_vm_t));
411	    if (njs_slow_path(nvm == NULL)) {
412	        goto fail;
413	    }
414	
415	    *nvm = *vm;
416	
417	    nvm->mem_pool = nmp;
418	    nvm->trace.data = nvm;
419	    nvm->external = external;
420	
421	    nvm->shared_atom_count = vm->atom_id_generator;
422	
423	    njs_flathsh_init(&nvm->atom_hash);
424	    nvm->atom_hash_current = &nvm->atom_hash;
425	
426	    ret = njs_vm_runtime_init(nvm);
427	    if (njs_slow_path(ret != NJS_OK)) {
428	        goto fail;
429	    }
430	
431	    ret = njs_vm_protos_init(nvm, &nvm->global_value);
432	    if (njs_slow_path(ret != NJS_OK)) {
433	        goto fail;
434	    }
435	
436	    global = njs_scope_make(nvm, nvm->global_scope->items);
437	    if (njs_slow_path(global == NULL)) {
438	        goto fail;
439	    }
440	
441	    if (nvm->options.unsafe) {
442	        nvm->scope_absolute = njs_arr_create(nvm->mem_pool,
443	                                             vm->scope_absolute->items,
444	                                             sizeof(njs_value_t *));
445	        if (njs_slow_path(nvm->scope_absolute == NULL)) {
446	            goto fail;
447	        }
448	
449	        value = njs_arr_add_multiple(nvm->scope_absolute,
450	                                     vm->scope_absolute->items);
451	        if (njs_slow_path(value == NULL)) {
452	            goto fail;
453	        }
454	
455	        memcpy(value, vm->scope_absolute->start,
456	               vm->scope_absolute->items * sizeof(njs_value_t *));
457	    }
458	
459	    nvm->levels[NJS_LEVEL_GLOBAL] = global;
460	
461	    /* globalThis and this */
462	    njs_scope_value_set(nvm, njs_scope_global_this_index(), &nvm->global_value);
463	
464	    nvm->levels[NJS_LEVEL_LOCAL] = NULL;
465	
466	    return nvm;
467	
468	fail:
